import{_ as t,c as a,a1 as o,o as i}from"./chunks/framework.BDxlaA_J.js";const p=JSON.parse('{"title":"Lab Building","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/0-core-knowledge/1-Lab-Building.md","filePath":"categories/ethical-hacking-labs/0-core-knowledge/1-Lab-Building.md"}'),r={name:"categories/ethical-hacking-labs/0-core-knowledge/1-Lab-Building.md"};function l(n,e,s,c,u,d){return i(),a("div",null,e[0]||(e[0]=[o('<h1 id="lab-building" tabindex="-1">Lab Building <a class="header-anchor" href="#lab-building" aria-label="Permalink to &quot;Lab Building&quot;">​</a></h1><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ul><li>Windows 10, macOS or any Linux distro <ul><li>At least 8 GB RAM (16GB recommended)</li></ul></li></ul><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Understand how virtual machines work</li><li>Learn how to create a basic virtual environment for pentesting purpose</li></ul><h1 id="what-does-virtual-machine-vm-means" tabindex="-1">What does Virtual Machine (VM) means? <a class="header-anchor" href="#what-does-virtual-machine-vm-means" aria-label="Permalink to &quot;What does Virtual Machine (VM) means?&quot;">​</a></h1><p>For simplicity, think of a virtual machine (VM) as a &quot;computer made of software&quot; which you can use to run any software you&#39;d run on a real, physical computer. Like a physical machine, a virtual machine has its own operating system (Windows, Linux, etc.), storage, networking, configuration settings, and software, and it is fully isolated from other virtual machines running on that host.</p><p><img src="https://miro.medium.com/max/937/1*QgshMdPQ7ZzK1hRbv1ncPQ.jpeg" alt="vm"></p><p><strong>Security benefits</strong> — Because virtual machines run in multiple operating systems, using a guest operating system on a VM allows you to run apps of questionable security and protects your host operating system. VMs also allow for better security forensics, pentesting and are often used to safely study computer viruses, isolating the viruses to avoid risking their host computer.</p><h3 id="hypervisors" tabindex="-1">Hypervisors <a class="header-anchor" href="#hypervisors" aria-label="Permalink to &quot;Hypervisors&quot;">​</a></h3><p>There are two main hypervisor types, referred to as <strong>“Type 1” (or “bare metal”)</strong> and <strong>“Type 2” (or “hosted”)</strong>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/0143eb15cf424c87ae823109d73df9ebe3faebec/hyper.png" alt="hypervisors"></p><ul><li><strong>Type 1</strong> hypervisor acts like a lightweight operating system and runs directly on the host’s hardware.</li><li><strong>Type 2</strong> hypervisor runs as a software layer on an operating system, like other computer programs.</li></ul><h1 id="_1-virtualbox-installation" tabindex="-1">1. VirtualBox Installation <a class="header-anchor" href="#_1-virtualbox-installation" aria-label="Permalink to &quot;1. VirtualBox Installation&quot;">​</a></h1><ul><li><strong>This tutorial use <a href="https://www.virtualbox.org" target="_blank" rel="noreferrer">Oracle VM VirtualBox</a>, the most popular free and open-source hosted hypervisor for x86 virtualization, developed by Oracle.</strong></li><li>There are other options from different vendors to achieve the same result: <ul><li><a href="https://www.vmware.com/products/workstation-player.html" target="_blank" rel="noreferrer">VMware Player for Windows (30 day trial)</a></li><li><a href="https://www.vmware.com/products/fusion.html" target="_blank" rel="noreferrer">VMware Fusion for macOS (30 day trial)</a></li><li><a href="https://docs.microsoft.com/en-us/virtualization/hyper-v-on-windows/about/" target="_blank" rel="noreferrer">Windows Hyper-V</a></li><li><a href="https://help.ubuntu.com/community/KVM/Installation" target="_blank" rel="noreferrer">Linux KVM</a></li></ul></li></ul><ol><li><strong>Make sure your PC support hardware virtualization (Windows)</strong><ul><li>Reboot your computer</li><li>Right when the computer is coming up from the black screen, press Delete, Esc, F1, F2, or F4. Each computer manufacturer uses a different key but it may show a brief message at boot telling you which one to press. If you miss it the first time, reboot and try again. It helps to tap the key about twice a second when the computer is coming up. If you are not able to enter the BIOS via this method, consult your computer’s manual.</li><li>In the BIOS settings, find the configuration items related to the CPU. These can be in under the headings Processor, Chipset, or Northbridge.</li><li>Enable virtualization; the setting may be called <strong>VT-x, AMD-V, SVM, or Vanderpool</strong>. Enable Intel VT-d or AMD IOMMU if the options are available.</li><li>Save your changes and reboot.</li></ul></li></ol><blockquote><p>⚠️ If you are unable to find the Virtualization settings in your BIOS it may mean that your computer does not support it.</p></blockquote><ol start="2"><li><p><strong>Download the latest version of Virtual Box</strong></p><ul><li>Go to Oracle Virtual Box website: <ul><li><a href="https://www.virtualbox.org/wiki/Downloads" target="_blank" rel="noreferrer">https://www.virtualbox.org/wiki/Downloads</a></li></ul></li><li>Select your current OS and download the installer</li><li><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/944dad38ad3bfc556600c6ca3e08ec83cabd54e5/vbox1.png" alt="v"></li><li>Also, scroll down on the same page and download the <strong>VirtualBox Extension Pack</strong>. This extension will allow VirtualBox functionalities like USB support, virtual disk encryption etc.</li><li><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/944dad38ad3bfc556600c6ca3e08ec83cabd54e5/vbox2.png" alt="v2"></li></ul></li><li><p><strong>Install Virtual Box and Extension Pack</strong></p><ul><li>There is no special configuration on the <strong>Virtual Box</strong> installation process, just point, click and install.</li><li>Once the installation is done, install the <strong>Extension Pack</strong> by double clicking it; The file extension is <code>.vbox-extpack</code>. Don&#39;t worry about the warning prompts.</li></ul></li></ol><h2 id="virtualbox-nat-configuration" tabindex="-1">VirtualBox NAT configuration <a class="header-anchor" href="#virtualbox-nat-configuration" aria-label="Permalink to &quot;VirtualBox NAT configuration&quot;">​</a></h2><p><em>The next steps will cover how to create a NAT network on VirtualBox. In simple words Virtual Machines needs a virtual network adapter, to access the internet and segragete your Host IP(main OS) and Guest IP(VM).</em></p><ol start="4"><li><strong>Launch VirtualBox and open the <code>Preferences</code> pane</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1b0a358d438d859df17db305753ce41c1826e4b0/pref1.png" alt="pref1"></p><ol start="5"><li><strong>Go to the <code>Network tab</code> on the left pane, and then click the <code>green plus button</code> on the right</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1b0a358d438d859df17db305753ce41c1826e4b0/pref2.png" alt="pref2"></p><ol start="6"><li><strong>By the default, VirtualBox automatically creates a NatNetwork. Click the <code>OK</code> button and save this configuration</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1b0a358d438d859df17db305753ce41c1826e4b0/pref3.png" alt="pref3"></p><ol start="7"><li><strong>Next part we will download the latest Kali Linux version and boot it up into Virtual box software</strong></li></ol><h2 id="about-kali-linux" tabindex="-1">About Kali Linux <a class="header-anchor" href="#about-kali-linux" aria-label="Permalink to &quot;About Kali Linux&quot;">​</a></h2><p><img src="https://www.bleepstatic.com/content/hl-images/2019/11/29/kali-header.jpg" alt="kali"></p><blockquote><p>⚠️ Kali Linux Tutorial will be covered on the next module [Linux for Hackers].md</p></blockquote><p>Kali Linux (formerly known as BackTrack Linux) is an open-source, Debian-based Linux distribution aimed at advanced Penetration Testing and Security Auditing. <a href="https://www.kali.org/docs/introduction/what-is-kali-linux/" target="_blank" rel="noreferrer">[+]</a></p><p>Kali Linux contains several hundred tools targeted towards various information security tasks, such as:</p><ul><li>Penetration Testing</li><li>Security Research</li><li>Computer Forensics</li><li>Reverse Engineering</li></ul><h2 id="download-the-latest-kali-linux-image" tabindex="-1">Download the latest Kali Linux image <a class="header-anchor" href="#download-the-latest-kali-linux-image" aria-label="Permalink to &quot;Download the latest Kali Linux image&quot;">​</a></h2><ol><li><strong>Go to Offensive Security website:</strong><ul><li><a href="https://www.offensive-security.com/kali-linux-vm-vmware-virtualbox-image-download/" target="_blank" rel="noreferrer">https://www.offensive-security.com/kali-linux-vm-vmware-virtualbox-image-download/</a></li></ul></li><li><strong>Download the Kali Linux VirtualBox image, make sure to select the <code>Virtual Box image (OVA)</code></strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/163a5fcc5653f6c06fb7e63fbf570e3fd9b5c144/kali0.png" alt="kali0"></p><h1 id="_2-installing-kali-linux-on-virtualbox" tabindex="-1">2. Installing Kali Linux on VirtualBox <a class="header-anchor" href="#_2-installing-kali-linux-on-virtualbox" aria-label="Permalink to &quot;2. Installing Kali Linux on VirtualBox&quot;">​</a></h1><p>Once you have installed VirtualBox and downloaded the Kali Linux image, you just need to import it to VirtualBox in order to make it work.</p><ol><li><strong>Launch VirtualBox and click the <code>Import Button</code> on the top center menu</strong></li></ol><p><img src="https://i1.wp.com/itsfoss.com/wp-content/uploads/2019/02/vmbox-import-kali-linux.jpg?w=956&amp;ssl=1" alt="kali1"></p><ol start="2"><li><strong>Next, browse the Kali Linux image (OVA) you just downloaded and choose it to be imported (as you can see in the image below).</strong></li></ol><p><img src="https://i2.wp.com/itsfoss.com/wp-content/uploads/2019/02/vmbox-linux-next.jpg?w=954&amp;ssl=1" alt="kali2"></p><ol start="3"><li><strong>Next, you will be shown the settings for the virtual machine you are about to import. So, you can customize them or not – that is your choice based on your hardware capacity.</strong><ul><li>If you have a computer with 8GB RAM and at least 2 cores available, leave the default settings.</li><li>If your computer have 16GB RAM or more, I recommend to use 4GB RAM on Kali Linux, to do that, scroll down the configuration list and change the <code>RAM value</code> to <code>4096</code> MB</li></ul></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9a53e3ba4ca62c777cf59acc53d211b4c187598e/pref4.png" alt="kali3"></p><ol start="4"><li><strong>You will now see the Kali box listed. So, just hit Start to launch it.</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/5f7c4d496d67f429aff72c1c177028f16dc35379/pref5.png" alt="kali4"></p><ol start="5"><li><strong>Type the default credentials:</strong> username: <code>kali</code>, password: <code>kali</code>. <ul><li>Tip: On Linux, you can change the default password of the current user by typing <code>passwd</code> on terminal.</li></ul></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/5f7c4d496d67f429aff72c1c177028f16dc35379/kali-log.png" alt="kali5"></p><ol start="6"><li><strong>Done!</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/a8f9a9f928ce6aeb71683cf95cb738b5842d0c04/kali-desk.png" alt="kali6"></p><ul><li>⚠️ <strong>Next module you&#39;ll learn some techniques of Kali distro and how to operate on Linux itself.</strong></li></ul>',51)]))}const g=t(r,[["render",l]]);export{p as __pageData,g as default};
